import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

import AnnotationTopBar from '../components/AnnotationTopBar';
import AnnotationCanvas from '../components/AnnotationCanvas';
import AnnotationListSidebar from '../components/AnnotationListSidebar';
import './Annotate.css';

export default function Annotate() {
  const navigate = useNavigate();
  const { state } = useLocation();
  const folderInfo = state?.folderInfo;

  if (!folderInfo) {
    return (
      <div style={{ padding: 20 }}>
        <h2>No folder info found. Please create a task first.</h2>
        <button onClick={() => navigate('/')}>Go Home</button>
      </div>
    );
  }

  const { folderId, taskName, labelClasses, files } = folderInfo;

  // -------------- Annotations for each image --------------
  const [annotations, setAnnotations] = useState({});
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  // Tools: move, bbox, polygon, polyline, point, ellipse, segmentation
  const [selectedTool, setSelectedTool] = useState('move');
  // For “segmentation” specifically, we have a small dropdown
  const [segmentationType, setSegmentationType] = useState('instance');

  const [selectedLabelClass, setSelectedLabelClass] = useState(
    labelClasses[0]?.name || ''
  );
  const [scale, setScale] = useState(1.0);

  const currentFileUrl = files[currentIndex]?.url;
  const currentShapes = annotations[currentFileUrl] || [];

  // Whenever shapes change, store old state in undoStack
  const handleAnnotationsChange = (newShapes) => {
    const updated = {
      ...annotations,
      [currentFileUrl]: newShapes,
    };
    setUndoStack([...undoStack, annotations]);
    setRedoStack([]);
    setAnnotations(updated);
  };

  // -------------- Undo / Redo --------------
  const undo = () => {
    if (undoStack.length === 0) return;
    const prev = undoStack[undoStack.length - 1];
    setRedoStack([...redoStack, annotations]);
    setUndoStack(undoStack.slice(0, -1));
    setAnnotations(prev);
  };

  const redo = () => {
    if (redoStack.length === 0) return;
    const next = redoStack[redoStack.length - 1];
    setUndoStack([...undoStack, annotations]);
    setRedoStack(redoStack.slice(0, -1));
    setAnnotations(next);
  };

  // -------------- Deletion & Update --------------
  const handleDeleteAnnotation = (index) => {
    const arr = [...currentShapes];
    arr.splice(index, 1);
    handleAnnotationsChange(arr);
  };

  const handleUpdateAnnotation = (index, changes) => {
    const arr = [...currentShapes];
    arr[index] = { ...arr[index], ...changes };
    handleAnnotationsChange(arr);
  };

  // -------------- Navigation --------------
  const handlePrev = () => {
    if (currentIndex > 0) setCurrentIndex((i) => i - 1);
  };
  const handleNext = () => {
    if (currentIndex < files.length - 1) setCurrentIndex((i) => i + 1);
  };

  // -------------- Zoom --------------
  const handleZoomIn = () => setScale((s) => Math.min(s + 0.1, 5));
  const handleZoomOut = () => setScale((s) => Math.max(s - 0.1, 0.2));
  const handleWheelZoom = (deltaY) => {
    if (deltaY < 0) handleZoomIn();
    else handleZoomOut();
  };

  // -------------- Save --------------
  const handleSave = async () => {
    const bodyData = {
      folderId,
      taskName,
      labelClasses,
      annotations,
    };
    try {
      const res = await fetch('http://localhost:4000/api/annotations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bodyData),
      });
      const data = await res.json();
      alert('Saved: ' + data.message);
    } catch (err) {
      console.error(err);
      alert('Error saving');
    }
  };

  // -------------- Keyboard Shortcuts --------------
  useEffect(() => {
    const handleKey = (e) => {
      const key = e.key;
      // Tools
      if (key === 'm' || key === 'M') {
        setSelectedTool('move');
      } else if (key === 'b' || key === 'B') {
        setSelectedTool('bbox');
      } else if (key === 'p' || key === 'P') {
        setSelectedTool('polygon');
      } else if (key === 'l' || key === 'L') {
        setSelectedTool('polyline');
      } else if (key === 'o' || key === 'O') {
        setSelectedTool('point');
      } else if (key === 'e' || key === 'E') {
        setSelectedTool('ellipse');
      } else if ((key === 's' || key === 'S') && e.ctrlKey) {
        // Ctrl+S => Save
        e.preventDefault();
        handleSave();
      } else if (key === 's' || key === 'S') {
        // Just S => segmentation
        setSelectedTool('segmentation');
      }
      // Esc => cancel shape
      if (key === 'Escape') {
        const event = new CustomEvent('cancel-annotation');
        window.dispatchEvent(event);
      }
      // Next / Prev
      if (key === 'ArrowRight') {
        handleNext();
      } else if (key === 'ArrowLeft') {
        handlePrev();
      }
      // Undo / Redo
      if (e.ctrlKey && (key === 'z' || key === 'Z')) {
        e.preventDefault();
        undo();
      } else if (e.ctrlKey && (key === 'y' || key === 'Y')) {
        e.preventDefault();
        redo();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
    // eslint-disable-next-line
  }, [annotations, undoStack, redoStack]);

  // -------------- Export Logic --------------
  const [exportOpen, setExportOpen] = useState(false);
  const openExport = () => setExportOpen(true);
  const closeExport = () => setExportOpen(false);

  const exportAnnotations = (format) => {
    if (format === 'coco') {
      downloadCOCO();
    } else if (format === 'yolo') {
      downloadYOLO();
    } else if (format === 'pascal') {
      downloadPascal();
    }
    closeExport();
  };

  function downloadFile(url, filename) {
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }
  function downloadCOCO() {
    alert('COCO export not yet implemented!');
  }
  function downloadYOLO() {
    alert('YOLO export not yet implemented!');
  }
  function downloadPascal() {
    alert('Pascal VOC export not yet implemented!');
  }

  // -------------- When annotation finishes => switch to move --------------
  const handleFinishShape = () => {
    setSelectedTool('move');
  };

  // -------------- Image Dimensions (for fill-empty-spaces) --------------
  const [imageWidth, setImageWidth] = useState(0);
  const [imageHeight, setImageHeight] = useState(0);

  // We'll receive these from <AnnotationCanvas> once the image is loaded
  const handleImageLoaded = (width, height) => {
    setImageWidth(width);
    setImageHeight(height);
  };

  // -------------- Fill Empty Spaces Logic --------------
  const [backgroundName, setBackgroundName] = useState('background');
  const [backgroundColor, setBackgroundColor] = useState('#000000'); // black

  // If black (#000000) is already used, pick near-black
  useEffect(() => {
    const isBlackUsed = labelClasses.some(
      (lc) => lc.color?.toLowerCase() === '#000000'
    );
    if (isBlackUsed) {
      setBackgroundColor('#111111'); // near-black
    }
  }, [labelClasses]);

  const handleBackgroundNameChange = (e) => {
    setBackgroundName(e.target.value); // no special logic; always
  };

  // The button that performs the fill
  const handleFillEmptySpaces = () => {
    // Always enabled, no need to check backgroundName emptiness
    const leftoverPolygons = computeEmptySpacePolygons(
      currentShapes,
      imageWidth,
      imageHeight
    );
    if (leftoverPolygons.length === 0) {
      alert('No unannotated area found.');
      return;
    }
    const newAnnots = [...currentShapes];
    leftoverPolygons.forEach((poly) => {
      newAnnots.push({
        type: 'polygon',
        points: poly.points,
        label: backgroundName || 'background',
        color: backgroundColor,
      });
    });
    handleAnnotationsChange(newAnnots);
    alert(`Filled empty spaces with "${backgroundName}" polygons!`);
  };

  return (
    <div className="annotate-container">
      <AnnotationTopBar
        onHome={() => navigate('/')}
        onPrev={handlePrev}
        onNext={handleNext}
        onSave={handleSave}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onExport={openExport}
        currentIndex={currentIndex}
        total={files.length}
        taskName={taskName}
      />

      <div style={{ padding: '8px', background: '#eee' }}>
        <button onClick={undo} style={{ marginRight: '8px' }}>
          Undo (Ctrl+Z)
        </button>
        <button onClick={redo} style={{ marginRight: '8px' }}>
          Redo (Ctrl+Y)
        </button>
      </div>

      <div className="annotate-main">
        {/* Tools Sidebar */}
        <div className="tools-sidebar">
          <h3>Tools</h3>
          <label>
            <input
              type="radio"
              name="tool"
              value="move"
              checked={selectedTool === 'move'}
              onChange={() => setSelectedTool('move')}
            />
            <span className="tool-icon">👆</span> Move (M)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="bbox"
              checked={selectedTool === 'bbox'}
              onChange={() => setSelectedTool('bbox')}
            />
            <span className="tool-icon">⬛</span> BBox (B)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polygon"
              checked={selectedTool === 'polygon'}
              onChange={() => setSelectedTool('polygon')}
            />
            <span className="tool-icon">🔺</span> Polygon (P)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polyline"
              checked={selectedTool === 'polyline'}
              onChange={() => setSelectedTool('polyline')}
            />
            <span className="tool-icon">📈</span> Polyline (L)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="point"
              checked={selectedTool === 'point'}
              onChange={() => setSelectedTool('point')}
            />
            <span className="tool-icon">📍</span> Point (O)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="ellipse"
              checked={selectedTool === 'ellipse'}
              onChange={() => setSelectedTool('ellipse')}
            />
            <span className="tool-icon">⬭</span> Ellipse (E)
          </label>

          {/* Segmentation */}
          <label>
            <input
              type="radio"
              name="tool"
              value="segmentation"
              checked={selectedTool === 'segmentation'}
              onChange={() => setSelectedTool('segmentation')}
            />
            <span className="tool-icon">🎨</span> Segmentation (S)
          </label>
          {selectedTool === 'segmentation' && (
            <div style={{ marginLeft: '20px', marginBottom: '8px' }}>
              <label style={{ display: 'block', marginBottom: '4px' }}>
                Type:
              </label>
              <select
                value={segmentationType}
                onChange={(e) => setSegmentationType(e.target.value)}
              >
                <option value="instance">Instance</option>
                <option value="semantic">Semantic</option>
                <option value="panoptic">Panoptic</option>
              </select>
            </div>
          )}

          <h3 style={{ marginTop: 16 }}>Active Label</h3>
          <select
            value={selectedLabelClass}
            onChange={(e) => setSelectedLabelClass(e.target.value)}
          >
            {labelClasses.map((lc, i) => (
              <option key={i} value={lc.name}>
                {lc.name}
              </option>
            ))}
          </select>

          <div className="note-area">
            <p><strong>Shortcuts:</strong></p>
            <ul>
              <li>M/B/P/L/O/E => Tools</li>
              <li>S => Segmentation</li>
              <li>Ctrl+S => Save</li>
              <li>Esc => Cancel shape</li>
              <li>ArrowLeft => Prev image</li>
              <li>ArrowRight => Next image</li>
              <li>Ctrl+Z => Undo</li>
              <li>Ctrl+Y => Redo</li>
              <li>Ctrl+C => Copy selected</li>
              <li>Ctrl+V => Paste annotation</li>
            </ul>
          </div>

          {/* Fill Empty Spaces UI */}
          {(segmentationType === 'instance' ||
            segmentationType === 'semantic' ||
            segmentationType === 'panoptic') && (
              <div style={{ marginTop: 16 }}>
                <h4>Fill Empty Spaces</h4>
                <p>Background Name:</p>
                <input
                  type="text"
                  value={backgroundName}
                  onChange={handleBackgroundNameChange}
                  placeholder="e.g. background"
                />
                <button
                  style={{ marginTop: 6 }}
                  onClick={handleFillEmptySpaces}
                >
                  Fill Empty Spaces
                </button>
              </div>
            )}
        </div>

        {/* Canvas */}
        <div className="canvas-area">
          {currentFileUrl ? (
            <AnnotationCanvas
              fileUrl={currentFileUrl}
              annotations={currentShapes}
              onAnnotationsChange={handleAnnotationsChange}
              selectedTool={selectedTool}
              scale={scale}
              onWheelZoom={handleWheelZoom}
              activeLabelColor={
                labelClasses.find((l) => l.name === selectedLabelClass)?.color ||
                '#ff0000'
              }
              onFinishShape={handleFinishShape}
              onDeleteAnnotation={handleDeleteAnnotation}
              activeLabel={selectedLabelClass}
              labelClasses={labelClasses}
              segmentationType={segmentationType}
              // New callback to pass back image size
              onImageLoaded={handleImageLoaded}
            />
          ) : (
            <div style={{ textAlign: 'center', margin: 'auto' }}>
              No images found
            </div>
          )}
        </div>

        <AnnotationListSidebar
          annotations={currentShapes}
          onDeleteAnnotation={handleDeleteAnnotation}
          onUpdateAnnotation={handleUpdateAnnotation}
          labelClasses={labelClasses}
        />
      </div>

      {exportOpen && (
        <div className="export-modal-backdrop">
          <div className="export-modal">
            <h2>Export Annotations</h2>
            <p>Select format:</p>
            <div className="export-buttons">
              <button onClick={() => exportAnnotations('coco')}>COCO</button>
              <button onClick={() => exportAnnotations('yolo')}>YOLO</button>
              <button onClick={() => exportAnnotations('pascal')}>Pascal VOC</button>
            </div>
            <button className="close-btn" onClick={closeExport}>
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * Compute polygons that represent the "unannotated" region
 * of the image.  For demonstration only, this function:
 *   1) Creates a bounding rectangle polygon for the entire image
 *   2) Subtracts the union of existing polygon annotations
 *      (In real usage, you'd need a polygon union & difference library
 *       to handle complex shapes, holes, multiple polygons, etc.)
 *
 * @param {Array} currentShapes - The array of annotation objects
 * @param {number} imgWidth - Width of the image
 * @param {number} imgHeight - Height of the image
 * @returns {Array} Array of leftover polygons, each with structure:
 *                  { points: [ {x,y}, {x,y}, ... ] }
 */
function computeEmptySpacePolygons(currentShapes, imgWidth, imgHeight) {
  if (!imgWidth || !imgHeight) return [];

  // Step 1: bounding rect polygon
  const boundingPoly = [
    { x: 0, y: 0 },
    { x: imgWidth, y: 0 },
    { x: imgWidth, y: imgHeight },
    { x: 0, y: imgHeight },
  ];

  // Step 2: Collect existing polygons
  const existingPolygons = currentShapes
    .filter((ann) => ann.type === 'polygon')
    .map((ann) => ann.points);

  // Step 3: Union all existing polygons (placeholder).
  // In a real scenario, you'd use a geometry library to get union.
  // For now, we just do no union => potential over-subtraction for overlaps.
  let unionPolygons = existingPolygons;

  // Step 4: Subtract unionPolygons from boundingPoly
  let leftover = [boundingPoly];
  for (const poly of unionPolygons) {
    leftover = leftover.flatMap((lp) => polygonDifference(lp, poly) || []);
  }

  // leftover is an array of polygons
  return leftover.map((polyPoints) => ({ points: polyPoints }));
}

function polygonDifference(subjectPoly, clipPoly) {
  // Very naive approach for demonstration:
  // bounding box intersection => subtract => either keep or remove subject
  const minX = Math.min(...clipPoly.map((p) => p.x));
  const maxX = Math.max(...clipPoly.map((p) => p.x));
  const minY = Math.min(...clipPoly.map((p) => p.y));
  const maxY = Math.max(...clipPoly.map((p) => p.y));

  const subjectBBminX = Math.min(...subjectPoly.map((p) => p.x));
  const subjectBBmaxX = Math.max(...subjectPoly.map((p) => p.x));
  const subjectBBminY = Math.min(...subjectPoly.map((p) => p.y));
  const subjectBBmaxY = Math.max(...subjectPoly.map((p) => p.y));

  // No bounding box overlap => no difference
  if (
    subjectBBmaxX < minX ||
    subjectBBminX > maxX ||
    subjectBBmaxY < minY ||
    subjectBBminY > maxY
  ) {
    return [subjectPoly];
  }

  // If bounding box fully covers subject => remove entire polygon
  if (
    subjectBBminX >= minX &&
    subjectBBmaxX <= maxX &&
    subjectBBminY >= minY &&
    subjectBBmaxY <= maxY
  ) {
    return [];
  }

  // Partial overlap => do partial bounding clip
  const clipped1 = sutherlandHodgmanClip(subjectPoly, [
    { side: 'left', x: minX },
    { side: 'right', x: maxX },
    { side: 'top', y: minY },
    { side: 'bottom', y: maxY },
  ]);
  if (clipped1.length > 0) {
    // intersection => remove entire subject
    return [];
  }
  // else keep it
  return [subjectPoly];
}

function sutherlandHodgmanClip(polygon, edges) {
  let outputList = polygon;
  edges.forEach((edge) => {
    const inputList = outputList;
    outputList = [];
    if (inputList.length === 0) return;

    for (let i = 0; i < inputList.length; i++) {
      const current = inputList[i];
      const prev = inputList[(i + inputList.length - 1) % inputList.length];

      const currentInside = isInside(current, edge);
      const prevInside = isInside(prev, edge);

      if (prevInside && currentInside) {
        outputList.push(current);
      } else if (prevInside && !currentInside) {
        const inter = computeIntersection(prev, current, edge);
        if (inter) outputList.push(inter);
      } else if (!prevInside && currentInside) {
        const inter = computeIntersection(prev, current, edge);
        if (inter) outputList.push(inter);
        outputList.push(current);
      }
    }
  });
  return outputList;

  function isInside(pt, e) {
    if (e.side === 'left') return pt.x >= e.x;
    if (e.side === 'right') return pt.x <= e.x;
    if (e.side === 'top') return pt.y >= e.y;
    if (e.side === 'bottom') return pt.y <= e.y;
    return true;
  }

  function computeIntersection(a, b, e) {
    const dx = b.x - a.x;
    const dy = b.y - a.y;
    let t;
    if (e.side === 'left' || e.side === 'right') {
      if (Math.abs(dx) < 1e-8) return null;
      t = (e.x - a.x) / dx;
      const y = a.y + t * dy;
      return { x: e.x, y };
    } else {
      if (Math.abs(dy) < 1e-8) return null;
      t = (e.y - a.y) / dy;
      const x = a.x + t * dx;
      return { x, y: e.y };
    }
  }
}
